1	// game-of-life.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	describe("Conway's Game of Life", () => {
6	  it("should return an empty set when no cells are alive", () => {
7	    expect(nextGeneration(new Set())).toEqual(new Set());
8	  });
9	  it("should kill a single living cell with no neighbors (underpopulation)", () => {
10	    expect(nextGeneration(new Set(["0,0"]))).toEqual(new Set());
11	  });
12	  it("should kill a living cell with only one neighbor (underpopulation)", () => {
13	    expect(nextGeneration(new Set(["0,0", "1,0"]))).toEqual(new Set());
14	  });
15	  it("should keep a living cell alive when it has two live neighbors", () => {
16	    expect(nextGeneration(new Set(["0,0", "1,0", "2,0"]))).toEqual(new Set(["1,0", "1,1", "1,-1"]));
17	  });
18	  it("should keep a living cell alive when it has three live neighbors", () => {
19	    expect(nextGeneration(new Set(["0,0", "1,0", "0,1", "1,1"]))).toEqual(new Set(["0,0", "1,0", "0,1", "1,1"]));
20	  });
21	  it.todo("should kill a living cell with more than three live neighbors (overpopulation)");
22	  it.todo("should bring a dead cell to life when it has exactly three live neighbors (reproduction)");
23	  it.todo("should handle cells with negative coordinates");
24	});
25

1	export const nextGeneration = (cells: Set<string>): Set<string> => {
2	  const neighborCounts = countLiveNeighbors(cells);
3	  const result = new Set<string>();
4	  for (const [key, count] of neighborCounts) {
5	    if (cellLivesNextGeneration(count, cells.has(key))) {
6	      result.add(key);
7	    }
8	  }
9	  return result;
10	};
11	
12	const parseCell = (cell: string): [number, number] => {
13	  const [xStr, yStr] = cell.split(",");
14	  return [Number(xStr), Number(yStr)];
15	};
16	
17	const formatCell = (x: number, y: number): string => `${x},${y}`;
18	
19	const countLiveNeighbors = (cells: Set<string>): Map<string, number> => {
20	  const neighborCounts = new Map<string, number>();
21	  for (const cell of cells) {
22	    const [x, y] = parseCell(cell);
23	    for (let dx = -1; dx <= 1; dx++) {
24	      for (let dy = -1; dy <= 1; dy++) {
25	        if (dx === 0 && dy === 0) continue;
26	        const key = formatCell(x + dx, y + dy);
27	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
28	      }
29	    }
30	  }
31	  return neighborCounts;
32	};
33	
34	const cellLivesNextGeneration = (liveNeighborCount: number, isAlive: boolean): boolean =>
35	  liveNeighborCount === 3 || (liveNeighborCount === 2 && isAlive);
